"use client";

import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";
import { motion } from "framer-motion";
import PageHeader from "@/components/PageHeader";
import Reveal from "@/components/Reveal";

const videoList = [
  {
    title: "Communication Skills Masterclass",
    duration: "42 min",
  },
  {
    title: "Leadership Fundamentals",
    duration: "35 min",
  },
  {
    title: "Time Management Deep Dive",
    duration: "28 min",
  },
  {
    title: "Entrepreneur Mindset Session",
    duration: "50 min",
  },
];

export default function VideosPage() {
  const { profile } = useAuth();
  const router = useRouter();

  const locked = profile?.paymentStatus !== "paid";

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.35 }}
      className="min-h-screen bg-gradient-to-br from-[#0A1220] to-[#020617] text-white p-6 md:p-10"
    >
      <PageHeader
        title="Video Sessions"
        subtitle="Watch recorded learning sessions and master real-world skills."
        icon="🎥"
      />

      {locked ? (
        <motion.div
          initial={{ scale: 0.9, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          className="relative mt-20 max-w-xl mx-auto p-[1px] 
                     bg-gradient-to-r from-yellow-400 via-orange-400 to-pink-500 
                     rounded-3xl"
        >
          <div className="bg-[#0B1224] text-white rounded-3xl p-10 text-center">
            <h2 className="text-2xl font-bold mb-3">
              🔒 Videos are Locked
            </h2>

            <p className="mb-6 text-gray-400">
              Unlock lifetime access to all recorded sessions
              with a one-time payment.
            </p>

            <button
              onClick={() => router.push("/dashboard/payment")}
              className="btn-primary px-8 py-3 rounded-xl font-semibold"
            >
              Unlock Now
            </button>
          </div>
        </motion.div>
      ) : (
        <Reveal>
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-8">
            {videoList.map((video, index) => (
              <motion.div
                key={index}
                whileHover={{ y: -8 }}
                transition={{ type: "spring", stiffness: 200 }}
                className="relative group cursor-pointer"
              >
                <div className="relative rounded-2xl overflow-hidden bg-white/10 border border-white/10 backdrop-blur-xl">

                  {/* Thumbnail */}
                  <div className="aspect-video bg-gradient-to-br from-blue-500/20 to-purple-500/20 flex items-center justify-center relative">
                    
                    {/* Play Icon */}
                    <motion.div
                      whileHover={{ scale: 1.1 }}
                      className="w-14 h-14 rounded-full bg-white/20 backdrop-blur-md flex items-center justify-center text-2xl"
                    >
                      ▶
                    </motion.div>

                    {/* Duration */}
                    <div className="absolute bottom-3 right-3 text-xs bg-black/70 px-2 py-1 rounded">
                      {video.duration}
                    </div>
                  </div>

                  {/* Info */}
                  <div className="p-5">
                    <h3 className="text-lg font-semibold group-hover:text-white transition">
                      {video.title}
                    </h3>

                    <p className="text-sm text-gray-400 mt-2">
                      Click to watch session
                    </p>
                  </div>

                </div>
              </motion.div>
            ))}
          </div>
        </Reveal>
      )}
    </motion.div>
  );
}